'use server';

import { verifySession } from '@/lib/session';
import { db } from '@/lib/db';
import { marketingService, PricingResult } from '@/services/marketing.service';
import { providerService } from '@/services/providers/provider.service';

export async function calculatePriceAction(
  serviceId: string,
  quantity: number,
  promoCodeStr?: string
): Promise<{ success: boolean; data?: PricingResult; error?: string }> {
  try {
    const session = await verifySession().catch(() => null);

    const result = await marketingService.calculatePrice(
      session?.userId || null,
      serviceId,
      quantity,
      promoCodeStr
    );

    return { success: true, data: result };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
}

export async function checkoutAction(
  serviceId: string,
  link: string,
  quantity: number,
  promoCodeStr?: string,
  runs?: number,
  interval?: number
): Promise<{ success: boolean; orderId?: string; error?: string }> {
  try {
    const session = await verifySession();
    if (!session) {
      return { success: false, error: 'Unauthorized' };
    }

    return await checkoutCore(session.userId, serviceId, link, quantity, promoCodeStr, runs, interval);
  } catch (error: any) {
    if (error.message === 'INSUFFICIENT_FUNDS') {
      return { success: false, error: 'Недостаточно средств на балансе' };
    }
    return { success: false, error: error.message };
  }
}

/** 
 * Internal core checkout logic decoupled from session context 
 * so it can be safely called by B2B handlers.
 */
export async function checkoutCore(
  userId: string,
  serviceId: string,
  link: string,
  quantity: number,
  promoCodeStr?: string,
  runs?: number,
  interval?: number
): Promise<{ success: boolean; orderId?: string; error?: string }> {
  try {
    // 1. Double check and calculate final price
    const pricing = await marketingService.calculatePrice(userId, serviceId, quantity, promoCodeStr);

    // 2. Wrap creation in transaction to prevent concurrency balance attacks
    const orderId = await db.$transaction(async (tx) => {
      // Re-fetch user lock inside transaction to ensure precise balance
      const lockUser = await tx.user.findUnique({
        where: { id: userId }
      });

      if (!lockUser || lockUser.balance < pricing.totalCents) {
        throw new Error('INSUFFICIENT_FUNDS');
      }

      // Deduct balance & increment totalSpent
      await tx.user.update({
        where: { id: userId },
        data: { 
          balance: { decrement: pricing.totalCents },
          totalSpent: { increment: pricing.totalCents } 
        }
      });

      // Consume Promo Code
      if (promoCodeStr) {
        await marketingService.consumePromoCode(tx, promoCodeStr);
      }

      // Create Order
      const newOrder = await tx.order.create({
        data: {
          userId,
          serviceId,
          link,
          quantity,
          status: 'PENDING',
          charge: pricing.totalCents,
          providerCost: pricing.providerCostCents,
          remains: quantity,
          runs,
          interval
        }
      });

      return newOrder.id;
    });

    // 3. Try to push it to provider immediately (Best Effort)
    try {
      const provider = await providerService.getDefaultProvider();
      
      // In a real SMM script we might need to map our Internal service ID to Provider's external ID
      // but here we just pass the ID as string.
      const externalRes = await provider.createOrder(serviceId, link, quantity, runs, interval);

      if (externalRes.success && externalRes.externalId) {
        await db.order.update({
          where: { id: orderId },
          data: { 
            externalId: externalRes.externalId,
            status: 'IN_PROGRESS'
          }
        });
      } else {
        await db.order.update({
          where: { id: orderId },
          data: { 
            error: externalRes.error || 'Failed to submit to provider',
            status: 'ERROR' 
          }
        });
      }
    } catch (e: any) {
      console.error('[Checkout] Provider submission error:', e);
      // Even if provider fails, order is saved securely as PENDING. A sync worker can retry later.
    }

    return { success: true, orderId };
  } catch (error: any) {
    throw error;
  }
}
